// src/components/PanelCliente.js
import React, { useState, useEffect } from 'react';
import { MapPin, Search } from 'lucide-react';
import { calcularDistanciaReal } from '../utils/shippingService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

// COORDENADAS FIJAS DEL LOCAL (Ajusta estas a la ubicación real de tu local)
const COORDS_LOCAL = { lat: -26.732479, lon: -65.267028 }; 

const PanelCliente = () => {
  const [ofertas, setOfertas] = useState([]);
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  const [distanciaReal, setDistanciaReal] = useState(0);
  const [direccionStr, setDireccionStr] = useState("");

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acc = [];
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      acc = [...acc, ...ofs.map(o => ({ ...o, nombreLocal: l.nombre, localId: l.id }))];
    });
    setOfertas(acc);
  }, []);

  // Función para simular la selección de una dirección (O usar una API de mapas)
  const confirmarDireccion = () => {
    // Aquí podrías integrar Google Maps Autocomplete. 
    // Por ahora, simulamos que al ingresar la dirección, el sistema obtiene la coordenada exacta.
    // Esto evita que el navegador "adivine" mal tu ubicación en PC.
    
    if (!direccionStr) return alert("Ingresa tu calle y altura");

    // SIMULACIÓN: En un sistema real, convertiríamos "Calle Falsa 123" a Lat/Lon
    // Supongamos que la dirección elegida está a 1.2km:
    const d = 1.2; 
    setDistanciaReal(d);
    alert(`Ubicación establecida a ${d} km del local.`);
  };

  const handlePagoExitoso = (totalPagado) => {
    const nuevoPedido = { id: `PED-${Date.now()}`, total: totalPagado, distancia: distanciaReal };
    setPedidos([nuevoPedido, ...pedidos]);
    setCart([]);
  };

  return (
    <div style={{ display: 'flex', gap: '30px', padding: '20px 5%', background: '#f8fafc', minHeight: '100vh' }}>
      <div style={{ flex: 1 }}>
        {/* BUSCADOR DE UBICACIÓN PARA EVITAR ERROR DE PC */}
        <div style={addressPicker}>
          <MapPin size={20} color="#e67e22" />
          <input 
            type="text" 
            placeholder="Ingresa tu dirección exacta (Ej: Av. Alem 100, Tafí Viejo)" 
            style={inputAddress}
            value={direccionStr}
            onChange={(e) => setDireccionStr(e.target.value)}
          />
          <button onClick={confirmarDireccion} style={btnConfirmar}>Confirmar</button>
        </div>

        <h2 style={{color: '#1e293b', margin: '20px 0'}}>Ofertas Disponibles</h2>
        <div style={gridStyle}>
          {ofertas.map(o => (
            <div key={o.id} style={cardStyle}>
              {o.imagen && <img src={o.imagen} style={imgStyle} alt="" />}
              <div style={{padding: '15px'}}>
                <small style={{color: '#64748b'}}>{o.nombreLocal}</small>
                <h4 style={{margin: '5px 0'}}>{o.producto}</h4>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                  <span style={{fontWeight: 'bold', fontSize: '1.2rem'}}>${o.precioNuevo}</span>
                  <button onClick={() => setCart([...cart, o])} style={btnAddToCart}>Agregar</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div style={{ width: '380px' }}>
        <Carrito 
          cart={cart} 
          setCart={setCart} 
          distanciaReal={distanciaReal} 
          onCheckout={handlePagoExitoso} 
        />
        {pedidos.map(p => <SeguimientoPedido key={p.id} pedido={p} />)}
      </div>
    </div>
  );
};

// Estilos del Buscador
const addressPicker = { display: 'flex', alignItems: 'center', background: 'white', padding: '10px 20px', borderRadius: '15px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', gap: '10px' };
const inputAddress = { flex: 1, border: 'none', outline: 'none', fontSize: '1rem' };
const btnConfirmar = { background: '#e67e22', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const cardStyle = { background: 'white', borderRadius: '15px', overflow: 'hidden', border: '1px solid #e2e8f0' };
const imgStyle = { width: '100%', height: '140px', objectFit: 'cover' };
const btnAddToCart = { background: '#1e293b', color: 'white', border: 'none', padding: '8px', borderRadius: '8px', cursor: 'pointer', fontSize: '0.8rem' };

export default PanelCliente;
